+            .cmp(&left.ev_score_millionths)
+            .then_with(|| left.campaign_id.cmp(&right.campaign_id))
+    });
+    ranked.into_iter().map(|entry| entry.campaign_id).collect()
+}
+
+fn rank_by_gain(results: &[CampaignResult]) -> Vec<String> {
